class Solution {
public:
    string smallestNumber(string pattern) {
        string result;
        for (int i = 0; i <= size(pattern); ++i) {
            if (!(i == size(pattern) || pattern[i] == 'I')) {
                continue;
            }
            const int start = size(result) + 1;
            for (int j = i + 1; j >= start; --j) {
                result.push_back('0' + j);
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

# constructive algorithms
class Solution(object):
    def smallestNumber(self, pattern):
        """
        :type pattern: str
        :rtype: str
        """
        result = []
        for i in xrange(len(pattern)+1):
            if not (i == len(pattern) or pattern[i] == 'I'):
                continue
            for x in reversed(range(len(result)+1, (i+1)+1)):
                result.append(x)
        return "".join(map(str, result))
